/**
 * @summary Replay pipeline state from audit logs at a given timestamp
 */
export const getReplayPipelineUrl = (
  jobId: number,
  params?: ReplayPipelineParams,
) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/pipeline/${jobId}/replay?${stringifiedParams}`
    : `/api/pipeline/${jobId}/replay`;
};

export const replayPipeline = async (
  jobId: number,
  params?: ReplayPipelineParams,
  options?: RequestInit,
): Promise<PipelineReplay> => {
  return customFetch<PipelineReplay>(getReplayPipelineUrl(jobId, params), {
    ...options,
    method: "GET",
  });
};

export const getReplayPipelineQueryKey = (
  jobId: number,
  params?: ReplayPipelineParams,
) => {
  return [
    `/api/pipeline/${jobId}/replay`,
    ...(params ? [params] : []),
  ] as const;
};

